import React, { useState, useEffect, useRef } from 'react';
import { FiUpload, FiSearch, FiFile, FiVideo, FiImage, FiFileText, FiCalendar, FiChevronLeft, FiChevronRight, FiCheckCircle, FiX } from 'react-icons/fi';

const UploadWork = ({ user }) => {
    const [works, setWorks] = useState([]);
    const [searchQuery, setSearchQuery] = useState('');
    const [selectedDate, setSelectedDate] = useState(new Date());
    const [isUploading, setIsUploading] = useState(false);
    const [viewWork, setViewWork] = useState(null);
    const [uploadData, setUploadData] = useState({ topic: '', description: '', file: null });
    const [showUploadModal, setShowUploadModal] = useState(false);
    const fileInputRef = useRef(null);

    // Date for calendar navigation
    const [currentMonth, setCurrentMonth] = useState(new Date());

    useEffect(() => {
        const savedWorks = localStorage.getItem(`uploaded_works_${user?.id}`);
        if (savedWorks) {
            setWorks(JSON.parse(savedWorks));
        }
    }, [user]);

    const handleFileSelect = (e) => {
        const file = e.target.files[0];
        if (!file) return;
        setUploadData({ ...uploadData, file: file, topic: file.name.split('.')[0] });
        setShowUploadModal(true);
    };

    const handlePublish = () => {
        const { file, topic, description } = uploadData;
        if (!file) return;

        setIsUploading(true);

        const reader = new FileReader();
        reader.onloadend = () => {
            const newWork = {
                id: Date.now(),
                topic: topic || file.name.split('.')[0],
                description: description,
                fileName: file.name,
                fileType: file.type,
                size: (file.size / (1024 * 1024)).toFixed(2) + " MB",
                uploadDate: new Date().toISOString().split('T')[0],
                timestamp: new Date().toLocaleTimeString(),
                content: reader.result // Store base64 content
            };

            const updatedWorks = [newWork, ...works];
            setWorks(updatedWorks);
            localStorage.setItem(`uploaded_works_${user?.id}`, JSON.stringify(updatedWorks));

            setIsUploading(false);
            setShowUploadModal(false);
            setUploadData({ topic: '', description: '', file: null });
        };
        reader.readAsDataURL(file);
    };

    const openFile = (work) => {
        if (!work.content) {
            alert("File content not available (Simulation Limit)");
            return;
        }

        const win = window.open();
        if (!win) {
            alert("Please allow popups to view files");
            return;
        }

        if (work.fileType.includes('image') || work.fileType.includes('pdf') || work.fileType.includes('video')) {
            win.document.write(`
                <html>
                    <head><title>${work.topic}</title><style>body{margin:0;background:#0a0a0b;display:flex;align-items:center;justify-content:center;height:100vh;overflow:hidden;}</style></head>
                    <body>
                        ${work.fileType.includes('image') ? `<img src="${work.content}" style="max-width:100%;max-height:100%;object-fit:contain;"/>` :
                    work.fileType.includes('pdf') ? `<embed src="${work.content}" type="application/pdf" width="100%" height="100%"/>` :
                        `<video src="${work.content}" controls style="max-width:100%;max-height:100%;"/>`}
                    </body>
                </html>
            `);
        } else {
            // For other types, try to trigger download/display
            const link = document.createElement('a');
            link.href = work.content;
            link.download = work.fileName;
            link.click();
            win.close();
        }
    };

    const filteredWorks = works.filter(work =>
        work.topic.toLowerCase().includes(searchQuery.toLowerCase())
    );

    // Calendar logic
    const getDaysInMonth = (date) => {
        const year = date.getFullYear();
        const month = date.getMonth();
        const days = new Array(new Date(year, month + 1, 0).getDate()).fill(0).map((_, i) => i + 1);
        return days;
    };

    const firstDayOfMonth = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), 1).getDay();
    const daysInMonth = getDaysInMonth(currentMonth);

    const prevMonth = () => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1, 1));
    const nextMonth = () => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 1));

    const hasUploadOnDate = (day) => {
        const dateStr = `${currentMonth.getFullYear()}-${String(currentMonth.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
        return works.some(w => w.uploadDate === dateStr);
    };

    const getFileIcon = (type) => {
        if (type.includes('video')) return <FiVideo className="text-purple-500" />;
        if (type.includes('image')) return <FiImage className="text-blue-500" />;
        if (type.includes('pdf')) return <FiFileText className="text-red-500" />;
        if (type.includes('sheet') || type.includes('excel')) return <FiFileText className="text-emerald-500" />;
        if (type.includes('presentation') || type.includes('powerpoint')) return <FiFileText className="text-orange-500" />;
        return <FiFile className="text-gray-500" />;
    };

    return (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 animate-fade-in">
            {/* Left: Upload & Search & List (2 cols) */}
            <div className="lg:col-span-2 space-y-8">
                <div className="bg-[#141417]/80 backdrop-blur-3xl rounded-[2.5rem] p-8 border border-white/5 shadow-2xl">
                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
                        <div>
                            <h3 className="text-2xl font-black text-white tracking-tight">Upload Portfolio</h3>
                            <p className="text-xs text-gray-500 font-black uppercase tracking-widest mt-1">Showcase your academic & creative work</p>
                        </div>
                        <button
                            onClick={() => fileInputRef.current.click()}
                            disabled={isUploading}
                            className="bg-blue-600 hover:bg-blue-500 text-white px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest transition-all shadow-[0_10px_30px_rgba(37,99,235,0.3)] flex items-center justify-center active:scale-95 disabled:opacity-50"
                        >
                            <FiUpload className="mr-3" size={18} />
                            {isUploading ? 'Scanning...' : 'Upload Work'}
                        </button>
                        <input
                            type="file"
                            ref={fileInputRef}
                            className="hidden"
                            onChange={handleFileUpload}
                            accept="video/*,image/*,.pdf,.doc,.docx,.xls,.xlsx,.ppt,.pptx"
                        />
                    </div>

                    <div className="relative mb-8">
                        <FiSearch className="absolute left-6 top-1/2 -translate-y-1/2 text-gray-500" size={20} />
                        <input
                            type="text"
                            placeholder="Search by topic name..."
                            className="w-full bg-white/5 border border-white/5 rounded-2xl py-5 pl-16 pr-8 text-sm font-bold text-white focus:outline-none focus:border-blue-500/50 transition-all"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                        />
                    </div>

                    <div className="space-y-4 max-h-[500px] overflow-y-auto pr-2 custom-scrollbar">
                        {filteredWorks.length > 0 ? (
                            filteredWorks.map((work) => (
                                <div
                                    key={work.id}
                                    onClick={() => setViewWork(work)}
                                    className="bg-white/5 hover:bg-white/[0.08] border border-white/5 p-6 rounded-[1.5rem] transition-all cursor-pointer group flex items-center justify-between"
                                >
                                    <div className="flex items-center space-x-6">
                                        <div className="w-14 h-14 bg-white/5 rounded-2xl flex items-center justify-center border border-white/5 text-2xl group-hover:scale-110 transition-transform">
                                            {getFileIcon(work.fileType)}
                                        </div>
                                        <div>
                                            <h4 className="font-black text-white text-lg tracking-tight group-hover:text-blue-400 transition-colors uppercase">{work.topic}</h4>
                                            <div className="flex items-center space-x-4 mt-1">
                                                <span className="text-[10px] font-black text-gray-500 uppercase tracking-widest flex items-center">
                                                    <FiCalendar className="mr-1.5" /> {work.uploadDate}
                                                </span>
                                                <span className="text-[10px] font-black text-blue-500/60 uppercase tracking-widest">
                                                    {work.size}
                                                </span>
                                            </div>
                                        </div>
                                    </div>
                                    <div className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                                        <FiChevronRight className="text-gray-400" />
                                    </div>
                                </div>
                            ))
                        ) : (
                            <div className="text-center py-20 bg-white/5 rounded-[2rem] border border-dashed border-white/10">
                                <FiFile className="mx-auto text-gray-700 mb-4" size={48} />
                                <p className="text-gray-500 font-black text-xs uppercase tracking-widest">No works found</p>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* Right: Calendar (1 col) */}
            <div className="space-y-8">
                <div className="bg-[#141417]/80 backdrop-blur-3xl rounded-[2.5rem] p-8 border border-white/5 shadow-2xl h-full">
                    <div className="flex items-center justify-between mb-8">
                        <h3 className="text-lg font-black text-white tracking-tight flex items-center">
                            <FiCalendar className="mr-3 text-blue-500" /> Activity
                        </h3>
                        <div className="flex space-x-2">
                            <button onClick={prevMonth} className="p-2 hover:bg-white/5 rounded-xl transition-all"><FiChevronLeft /></button>
                            <button onClick={nextMonth} className="p-2 hover:bg-white/5 rounded-xl transition-all"><FiChevronRight /></button>
                        </div>
                    </div>

                    <div className="text-center mb-6">
                        <span className="text-xs font-black text-gray-500 uppercase tracking-[0.2em]">
                            {currentMonth.toLocaleString('default', { month: 'long' })} {currentMonth.getFullYear()}
                        </span>
                    </div>

                    <div className="grid grid-cols-7 gap-1 mb-2">
                        {['S', 'M', 'T', 'W', 'T', 'F', 'S'].map(d => (
                            <div key={d} className="text-[10px] font-black text-gray-700 text-center py-2">{d}</div>
                        ))}
                    </div>

                    <div className="grid grid-cols-7 gap-2">
                        {Array(firstDayOfMonth).fill(null).map((_, i) => (
                            <div key={`empty-${i}`} className="aspect-square"></div>
                        ))}
                        {daysInMonth.map(day => {
                            const hasUpload = hasUploadOnDate(day);
                            const isToday = day === new Date().getDate() &&
                                currentMonth.getMonth() === new Date().getMonth() &&
                                currentMonth.getFullYear() === new Date().getFullYear();

                            return (
                                <div
                                    key={day}
                                    className={`aspect-square rounded-xl flex items-center justify-center text-xs font-bold relative transition-all
                                        ${isToday ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/20' : 'bg-white/5 text-gray-400'}
                                        ${hasUpload ? 'border border-emerald-500/30 bg-emerald-500/5' : ''}
                                    `}
                                >
                                    {day}
                                    {hasUpload && (
                                        <div className="absolute -top-1 -right-1 w-4 h-4 bg-emerald-500 rounded-full flex items-center justify-center border-2 border-[#141417]">
                                            <FiCheckCircle size={8} className="text-white" />
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>

                    <div className="mt-10 p-6 bg-blue-500/5 rounded-2xl border border-blue-500/10">
                        <div className="flex items-center justify-between mb-4">
                            <span className="text-[10px] font-black text-blue-500 uppercase tracking-widest">Global Stats</span>
                            <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
                        </div>
                        <div className="text-3xl font-black text-white mb-1">{works.length}</div>
                        <div className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">Total Uploads</div>
                    </div>
                </div>
            </div>

            {/* View Modal */}
            {viewWork && (
                <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-[#0a0a0b]/90 backdrop-blur-xl animate-fade-in">
                    <div className="bg-[#141417] rounded-[3rem] shadow-[0_20px_80px_rgba(0,0,0,0.8)] w-full max-w-lg border border-white/5 overflow-hidden">
                        <div className="p-10 text-center">
                            <div className="w-24 h-24 bg-white/5 rounded-[2rem] flex items-center justify-center mx-auto mb-8 border border-white/5 text-5xl">
                                {getFileIcon(viewWork.fileType)}
                            </div>
                            <h3 className="text-3xl font-black text-white tracking-tight mb-2 uppercase">{viewWork.topic}</h3>
                            {viewWork.description && (
                                <div className="bg-white/5 p-6 rounded-2xl border border-white/5 text-left mb-8">
                                    <span className="block text-[8px] font-black text-blue-500 uppercase tracking-widest mb-2">Work Narrative</span>
                                    <p className="text-sm font-medium text-gray-400 leading-relaxed italic">"{viewWork.description}"</p>
                                </div>
                            )}

                            <div className="flex flex-col space-y-4">
                                <button
                                    onClick={() => openFile(viewWork)}
                                    className="w-full py-5 bg-white text-black font-black rounded-2xl text-xs uppercase tracking-widest hover:bg-blue-500 hover:text-white transition-all transform active:scale-95 shadow-xl shadow-black/20"
                                >
                                    View Asset
                                </button>
                                <button onClick={() => setViewWork(null)} className="w-full py-5 bg-white/5 text-gray-400 font-black rounded-2xl text-xs uppercase tracking-widest hover:bg-red-500/10 hover:text-red-500 transition-all border border-white/5">
                                    Close Preview
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}

            <style dangerouslySetInnerHTML={{
                __html: `
                .custom-scrollbar::-webkit-scrollbar { width: 4px; }
                .custom-scrollbar::-webkit-scrollbar-track { background: rgba(255, 255, 255, 0.02); border-radius: 10px; }
                .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(59, 130, 246, 0.2); border-radius: 10px; }
                .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(59, 130, 246, 0.4); }
            `}} />
        </div>
    );
};

export default UploadWork;
